mapper.select:
SELECT l.id, l.site_id, s.title AS site_title, l.user_id, u.username, l.ip, l.create_time FROM site_like l LEFT JOIN site s ON l.site_id = s.id LEFT JOIN sys_user u ON l.user_id = u.id
AND l.site_id = #{dto.siteId}
AND l.user_id = #{dto.userId}
ORDER BY l.create_time DESC

SELECT DATE(create_time) AS statDate, COUNT(*) AS count
FROM site_like
WHERE create_time >= #{startTime}
  AND create_time < #{endTime}
GROUP BY DATE(create_time)
ORDER BY statDate
